sm1: {
  es: { description:"Aquí comienza todo. Musgo marino puro, remojado toda la noche y licuado con agua de manantial hasta obtener un gel sedoso e inodoro que se convierte en la base de cada receta.", tip:"Usa siempre agua de manantial — el agua del grifo contiene cloro y flúor que pueden interferir con el contenido mineral del musgo.", shelfLife:"Refrigera en frasco sellado hasta 3 semanas. Congela en bandejas de hielo hasta 3 meses.", dailyUse:"Añade 1–2 cucharadas a tu batido, jugo o té matutino. Sin sabor ni olor.", benefits:["102 minerales y vitaminas","Apoyo tiroideo","Salud intestinal","Sistema inmunológico","Producción de colágeno","Antiinflamatorio"], steps:["Enjuaga bien el musgo bajo agua fría corriente.","Coloca en tazón de vidrio cubierto con agua de manantial — triplicará su tamaño.","Refrigera toda la noche (8–12 horas).","Escurre y enjuaga.","Licúa con ½ taza de agua fresca durante 1–2 minutos.","Vierte en frasco de vidrio y refrigera.","Usa 1–2 cucharadas diarias."] },
  fr: { description:"C'est ici que tout commence. De la mousse marine pure, trempée toute la nuit et mixée avec de l'eau de source pour obtenir un gel soyeux et inodore.", tip:"Utilisez toujours de l'eau de source — l'eau du robinet contient du chlore et du fluor.", shelfLife:"Réfrigérer dans un bocal hermétique jusqu'à 3 semaines. Congeler dans des bacs à glaçons jusqu'à 3 mois.", dailyUse:"Ajoutez 1–2 c. à soupe à votre smoothie, jus ou thé du matin.", benefits:["102 minéraux et vitamines","Soutien thyroïdien","Santé intestinale","Système immunitaire","Production de collagène","Anti-inflammatoire"], steps:["Rincez soigneusement la mousse sous l'eau froide.","Placez dans un bol en verre couvert d'eau de source — elle va tripler de volume.","Réfrigérez toute la nuit (8–12 heures).","Égouttez et rincez.","Mixez avec ½ tasse d'eau fraîche pendant 1–2 minutes.","Versez dans un bocal et réfrigérez.","Utilisez 1–2 c. à soupe par jour."] },
  pt: { description:"É aqui que tudo começa. Musgo marinho puro, deixado de molho durante a noite e misturado com água de nascente até formar um gel sedoso e inodoro.", tip:"Sempre use água de nascente — a água da torneira contém cloro e flúor.", shelfLife:"Refrigere em vidro lacrado por até 3 semanas. Congele em forminhas por até 3 meses.", dailyUse:"Adicione 1–2 colheres ao smoothie, suco ou chá da manhã.", benefits:["102 minerais e vitaminas","Suporte à tireoide","Saúde intestinal","Sistema imunológico","Produção de colágeno","Anti-inflamatório"], steps:["Enxágue bem o musgo sob água fria.","Coloque em tigela coberta com água de nascente — triplicará.","Refrigere overnight (8–12 horas).","Escorra e enxágue.","Bata com ½ xícara de água fresca por 1–2 minutos.","Despeje em vidro e refrigere.","Use 1–2 colheres diariamente."] },
  ht: { description:"Se la tout kòmanse. Mous lanmè pi, tranpe tout nuit, epi melanje ak dlo sous pou fè yon jèl swa san odè.", tip:"Toujou itilize dlo sous — dlo robinè gen klò ak fliyò.", shelfLife:"Mete nan frijidè nan veso fèmen jouk 3 semèn. Konjele nan bac glas jouk 3 mwa.", dailyUse:"Ajoute 1–2 kiyè nan smoothie, ji, oswa tè maten ou.", benefits:["102 minéral ak vitamin","Sipò glann tiroyid","Sante trip","Sistèm iminite","Pwodiksyon kolajen","Anti-enflamatwa"], steps:["Rense mous anba dlo frèt.","Mete nan bòl vè ak dlo sous — li pral triple.","Mete nan frijidè tout nuit (8–12 èdtan).","Vide epi rense.","Blende ak ½ tas dlo frèch 1–2 minit.","Vide nan veso epi mete nan frijidè.","Itilize 1–2 kiyè chak jou."] },
  jm: { description:"Dis is weh everyting start. Pure Irish moss, soak overnight, blend wid spring water inna silky odorless gel.", tip:"Always use spring water — tap water have chlorine and fluoride weh can mess wid di mineral content.", shelfLife:"Keep inna sealed glass jar inna fridge up to 3 weeks. Freeze inna ice cube tray fi up to 3 months.", dailyUse:"Add 1–2 tablespoon to yuh morning smoothie, juice, or tea.", benefits:["102 minerals & vitamins","Thyroid support","Gut health","Immune system","Collagen production","Anti-inflammatory"], steps:["Rinse di sea moss under cold running water.","Place inna glass bowl covered wid spring water — it will triple.","Refrigerate overnight (8–12 hours).","Drain and rinse.","Blend wid ½ cup fresh spring water fi 1–2 minutes.","Pour inna glass jar and refrigerate.","Use 1–2 tablespoon daily."] },
},
